    cursor: pointer;
    padding: 4px 6px;
    transition: background 0.15s;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

@using sv_fcb436dedd54458f9499f82424ad0c7b.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="() => OnSelect.InvokeAsync()">
    <div class="channel-name-row">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-desc">@TruncateDescription(Channel.Description)</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnSelect { get; set; }

    private static string TruncateDescription(string desc)
        => desc.Length > 40 ? desc[..40] + "…" : desc;
}

.channel-item {
    padding: 10px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 8px;
    transition: background 0.15s;
}

.channel-item:hover {
    background: rgba(255,255,255,0.1);
}

.channel-item.active {
    background: rgba(255,255,255,0.2);
}

.channel-name-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 15px;
    color: #e0e0e0;
}

.channel-item.active .channel-name {
    color: #fff;
}

.unread-badge {
    background: #e74c3c;
    color: #fff;
    font-size: 11px;
    font-weight: 700;
    padding: 1px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-desc {
    font-size: 12px;
    color: #aaa;
    margin-top: 2px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

