toolArgs.file_text:
.message-bubble {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background 0.15s;
}

.message-bubble:hover {
    background: #f5f5f5;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 15px;
    color: #1a1a1a;
}

.timestamp {
    font-size: 12px;
    color: #888;
}

.message-content {
    font-size: 15px;
    line-height: 1.5;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    border: 1px solid #ddd;
    border-radius: 12px;
    font-size: 13px;
    cursor: pointer;
    background: #f8f8f8;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #e8e8ff;
    border-color: #aac;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 2px 8px;
    font-size: 13px;
    color: #4a76a8;
    background: none;
    border: none;
    cursor: pointer;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    padding: 2px;
}

.action-btn {
    padding: 4px 10px;
    font-size: 12px;
    background: none;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    white-space: nowrap;
}

.action-btn:hover {
    background: #f0f0f0;
}

.emoji-picker {
    position: absolute;
    top: -44px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.15);
    padding: 4px;
}

.emoji-btn {
    font-size: 20px;
    background: none;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    padding: 4px 6px;
    transition: background 0.15s;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

