arguments.file_text:
namespace sv_fcb436dedd54458f9499f82424ad0c7b.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_fcb436dedd54458f9499f82424ad0c7b.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnSelect="() => OnChannelSelected.InvokeAsync(channel.Id)" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #2c2f33;
    color: #ddd;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid rgba(255,255,255,0.1);
}

.sidebar-header h3 {
    margin: 0;
    font-size: 18px;
    font-weight: 700;
    color: #fff;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

@using sv_fcb436dedd54458f9499f82424ad0c7b.Services

<div class="message-panel">
    <div class="panel-header">
        <h2># @ChannelName</h2>
        @if (!string.IsNullOrWhiteSpace(ChannelDescription))
        {
            <span class="panel-description">@ChannelDescription</span>
        }
    </div>

    <div class="message-list" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageBubble Message="msg"
                           Thread="GetThreadSummary(msg.Id)"
                           OnReply="() => OnOpenThread.InvokeAsync(msg.Id)"
                           OnViewThread="() => OnOpenThread.InvokeAsync(msg.Id)"
                           OnReact="(emoji) => OnReact.InvokeAsync((msg.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  ButtonText="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ThreadSummary? GetThreadSummary(int messageId)
        => ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);

    private async Task HandleScroll(EventArgs e)
    {
        // Scroll-to-top triggers loading more messages.
        // The JS-free approach: we invoke OnLoadMore; the parent decides if there's more to load.
        // A real implementation would use JS interop to detect scrollTop === 0.
        // For now the parent can wire this up with JS interop as needed.
    }
}

.message-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.panel-header {
    display: flex;
    align-items: baseline;
    gap: 12px;
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.panel-header h2 {
    margin: 0;
    font-size: 18px;
    font-weight: 700;
    color: #1a1a1a;
}

.panel-description {
    font-size: 13px;
    color: #888;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 0;
    display: flex;
    flex-direction: column;
    gap: 4px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 13px;
    color: #888;
}

@using sv_fcb436dedd54458f9499f82424ad0c7b.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>
    }

    <div class="thread-replies">
        @if (ThreadMessages is not null)
        {
            @foreach (var reply in ThreadMessages)
            {
                <MessageBubble Message="reply"
                               OnReact="(emoji) => OnReact.InvokeAsync((reply.Id, emoji))" />
            }
        }
    </div>

    <MessageInput Placeholder="Reply…"
                  ButtonText="Reply"
                  OnSend="OnSendReply" />
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message>? ThreadMessages { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fafafa;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 18px;
    cursor: pointer;
    color: #888;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background 0.15s;
}

.close-btn:hover {
    background: #e0e0e0;
    color: #333;
}

.thread-root {
    padding: 12px 16px;
    background: #f0f0f0;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.root-author {
    font-weight: 700;
    font-size: 14px;
    margin-bottom: 4px;
}

.root-content {
    font-size: 14px;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

