{"file_text": ".thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fafafa;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 18px;
    cursor: pointer;
    color: #888;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background 0.15s;
}

.close-btn:hover {
    background: #e0e0e0;
    color: #333;
}

.thread-root {
    padding: 12px 16px;
    background: #f0f0f0;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.root-author {
    font-weight: 700;
    font-size: 14px;
    margin-bottom: 4px;
}

.root-content {
    font-size: 14px;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}
