@using sv_fcb436dedd54458f9499f82424ad0c7b.Services

<div class="message-panel">
    <div class="panel-header">
        <h2># @ChannelName</h2>
        @if (!string.IsNullOrWhiteSpace(ChannelDescription))
        {
            <span class="panel-description">@ChannelDescription</span>
        }
    </div>

    <div class="message-list" @onscroll="HandleScroll">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        @foreach (var msg in Messages)
        {
            <MessageBubble Message="msg"
                           Thread="GetThreadSummary(msg.Id)"
                           OnReply="() => OnOpenThread.InvokeAsync(msg.Id)"
                           OnViewThread="() => OnOpenThread.InvokeAsync(msg.Id)"
                           OnReact="(emoji) => OnReact.InvokeAsync((msg.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  ButtonText="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public List<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ThreadSummary? GetThreadSummary(int messageId)
        => ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);

    private async Task HandleScroll(EventArgs e)
    {
        // Scroll-to-top triggers loading more messages.
        // The JS-free approach: we invoke OnLoadMore; the parent decides if there's more to load.
        // A real implementation would use JS interop to detect scrollTop === 0.
        // For now the parent can wire this up with JS interop as needed.
    }
}

