arguments.file_text:
.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    display: flex;
}

@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_fcb436dedd54458f9499f82424ad0c7b.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <div class="sidebar-col">
        <ChannelSidebar Channels="channels"
                        SelectedChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-col @(threadRootId.HasValue ? "" : "expanded")">
        @if (selectedChannel is not null)
        {
            <MessagePanel ChannelName="@selectedChannel.Name"
                          ChannelDescription="@selectedChannel.Description"
                          Messages="messages"
                          ThreadSummaries="threadSummaries"
                          IsLoadingMore="isLoadingMore"
                          OnOpenThread="OpenThread"
                          OnReact="HandleReaction"
                          OnSendMessage="SendMessage"
                          OnLoadMore="LoadMoreMessages" />
        }
        else
        {
            <div class="empty-state">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadRootId.HasValue)
    {
        <div class="thread-col">
            <ThreadPanel RootMessage="threadRootMessage"
                         ThreadMessages="threadMessages"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnReact="HandleReaction" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];
    private Channel? selectedChannel;
    private int selectedChannelId;

    // Thread state
    private int? threadRootId;
    private Message? threadRootMessage;
    private List<Message>? threadMessages;

    // Pagination
    private const int PageSize = 50;
    private int loadedCount;
    private bool isLoadingMore;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        loadedCount = 0;
        messages = [];
        threadSummaries = [];
        CloseThreadInternal();

        await LoadMessages();
        await ChatService.MarkChannelReadAsync(channelId);

        // Update the local unread count to 0
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMessages()
    {
        var newMessages = await ChatService.GetMessagesAsync(selectedChannelId, loadedCount, PageSize);
        messages.InsertRange(0, newMessages);
        loadedCount += newMessages.Count;
        BuildThreadSummaries();
    }

    private async Task LoadMoreMessages()
    {
        if (isLoadingMore) return;
        isLoadingMore = true;
        try
        {
            await LoadMessages();
        }
        finally
        {
            isLoadingMore = false;
        }
    }

    private async Task SendMessage(string content)
    {
        var msg = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootId = rootMessageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        BuildThreadSummaries();
    }

    private void CloseThread()
    {
        CloseThreadInternal();
    }

    private void CloseThreadInternal()
    {
        threadRootId = null;
        threadRootMessage = null;
        threadMessages = null;
    }

    private async Task SendThreadReply(string content)
    {
        if (!threadRootId.HasValue) return;
        var reply = await ChatService.SendMessageAsync(selectedChannelId, content, threadRootId.Value);
        threadMessages?.Add(reply);
        BuildThreadSummaries();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic update: add the reaction locally
        UpdateReactionInList(messages, args.MessageId, args.Emoji);
        if (threadMessages is not null)
        {
            UpdateReactionInList(threadMessages, args.MessageId, args.Emoji);
        }
    }

    private static void UpdateReactionInList(List<Message> list, int messageId, string emoji)
    {
        var idx = list.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = list[idx];
        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private void BuildThreadSummaries()
    {
        // Build thread summaries from messages that have replies
        var replyGroups = messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value);

        threadSummaries = replyGroups.Select(g => new ThreadSummary(
            RootMessageId: g.Key,
            ReplyCount: g.Count(),
            LastReplyAt: g.Max(m => m.SentAt)
        )).ToList();
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    width: 100%;
    overflow: hidden;
}

.sidebar-col {
    width: 20%;
    min-width: 200px;
    max-width: 300px;
    flex-shrink: 0;
}

.main-col {
    flex: 1;
    min-width: 0;
}

.main-col.expanded {
    /* When no thread is open, main takes remaining space */
}

.thread-col {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

.empty-state {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #888;
    font-size: 16px;
}

.chat-layout {
    height: 100vh;
    width: 100vw;
    overflow: hidden;
    display: flex;
}

