+
+.sidebar-col {
+    width: 20%;
+    min-width: 200px;
+    max-width: 300px;
+    flex-shrink: 0;
+}
+
+.main-col {
+    flex: 1;
+    min-width: 0;
+}
+
+.main-col.expanded {
+    /* When no thread is open, main takes remaining space */
+}
+
+.thread-col {
+    width: 25%;
+    min-width: 280px;
+    max-width: 400px;
+    flex-shrink: 0;
+}
+
+.empty-state {
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    height: 100%;
+    color: #888;
+    font-size: 16px;
+}
